ItemListener = {}

function ItemListener:init()
    --PlacingConsumeBlockEvent.registerCallBack(self.onPlacingConsumeBlock)
    ItemFoodUseEvent.registerCallBack(self.onItemFoodUse)
    EntityDeathDropItemEvent.registerCallBack(self.onDeathDropItem)
    EntityItemSpawnEvent.registerCallBack(self.onEntityItemSpawn)
    ClearDropItemEvent.registerCallBack(self.onClearDropItem)
    ClearInventoryEvent.registerCallBack(self.onClearInventory)
    ChestOpenEvent.registerCallBack(self.onChestOpen)
    PlayerExchangeItemEvent.registerCallBack(self.onPlayerExchangeItem)
end

function ItemListener.onItemFoodUse(pStack, pPlayer, pos)
    if not pStack or not pPlayer then
        return
    end

    local itemID = pStack.itemID
    local entityId = pPlayer:hashCode()

    if not(ItemListener:isMusicBox(itemID)) then
        return true
    end

    local config = ItemsConfig:getItemsByItemId(itemID)
    if config == nil then
        return true
    end

    local musicBox = GameMusicBox.new(pos, config, entityId)
    MusicBoxManager:addMusicBox(musicBox)

    pStack:decItemStackSize(1)

    return false
end

