function ItemListener.onDeathDropItem(entityId, damageType)
    local player = PlayerManager:getPlayerByEntityId(entityId)
    if player then
        player:createChest()
    end
    return true
end

function ItemListener.onEntityItemSpawn(itemID, itemDamage, stringValue, boolValue)
    return false
end

function ItemListener.onClearDropItem(itemID, itemDamage, clearType, itemCount, entityId)
    if clearType == 1 then
        local player = PlayerManager:getPlayerByEntityId(entityId)
        if player then
            return player:onDropItem(itemID, itemDamage, itemCount)
        end
    end

    if clearType == 2 then
        return false
    end

    return true
end

